import{_ as n}from"./plugin-vue_export-helper-x3n3nnut.js";import{o as s,c as a,e}from"./app-VLgNDF8W.js";const t="/blogs/assets/arraybuffer_layout.drawio-fYX9Hg5y.png",p={},o=e('<h1 id="arraybuffer" tabindex="-1"><a class="header-anchor" href="#arraybuffer" aria-hidden="true">#</a> ArrayBuffer</h1><p>JavaScript 可以通过类型化数组操作原始的二进制数据，JavaScript 类型化数组中的每一个元素都是原始二进制值，而二进制值采用多种支持的格式之一（从 8 位整数到 64 位浮点数）。</p><p>JavaScript 类型化数组将实现拆分为缓冲和视图两部分。缓冲（由 <code>ArrayBuffer</code> 对象实现）描述一个数据分块。可通过视图访问缓存对象中包含的内存，视图提供了上下文（即数据类型、起始偏移量和元素数）将数据转换为实际有类型的数组。</p><ul><li><code>ArrayBuffer</code> 对象：用来表示通用的、固定长度的原始二进制数据缓冲区。</li><li><code>TypedArray</code> 视图：从 <code>ArrayBuffer</code> 对象中<strong>读写简单类型</strong>的二进制数据。包含类型的视图如下： <ul><li><code>Int8Array</code> ：8 位有符号整型（补码），长度 1 字节。</li><li><code>Uint8Array</code> ：8 位无符号整型，长度 1 字节。</li><li><code>Uint8ClampedArray</code> ：8 位无符号整型，长度 1 字节。</li><li><code>Int16Array</code> ：16 位有符号整型（补码），长度 2 字节。</li><li><code>Uint16Array</code> ：16 位无符号整型，长度 2 字节。</li><li><code>Int32Array</code> ：32 位有符号整型（补码），长度 4 字节。</li><li><code>Uint32Array</code> ：32 位无符号整型，长度 4 字节。</li><li><code>Float32Array</code> ：32 位 IEEE 浮点数（7 位有效数字），长度 4 字节。</li><li><code>Float64Array</code> ：64 位 IEEE 浮点数（16 位有效数字），长度 8 字节。</li><li><code>BigInt64Array</code> ：64 位有符号整型（补码），长度 8 字节。</li><li><code>BigUint64Array</code> ：64 位无符号整型，长度 8 字节。</li></ul></li><li><code>DataView</code> 视图：从 <code>ArrayBuffer</code> 对象中<strong>读写复杂类型</strong>的二进制数据。比如第一个字节是 <code>Uint8Array</code>，第二、三个字节是 <code>Int16Array</code>、第四个字节开始是 <code>Float32Array</code>（32 位浮点数）等，此外还可以自定义字节序。</li></ul><p><img src="'+t+`" alt="arraybuffer_layout"></p><h2 id="arraybuffer-对象" tabindex="-1"><a class="header-anchor" href="#arraybuffer-对象" aria-hidden="true">#</a> ArrayBuffer 对象</h2><h3 id="arraybuffer-对象概述" tabindex="-1"><a class="header-anchor" href="#arraybuffer-对象概述" aria-hidden="true">#</a> ArrayBuffer 对象概述</h3><p><code>ArrayBuffer</code> 对象用来表示通用的、固定长度的原始二进制数据缓冲区。只能通过视图（<code>TypedArray</code> 视图和 <code>DataView</code> 视图）来读写，视图的作用是以指定格式解读二进制数据。</p><p><code>new ArrayBuffer(length, options)</code> 构造函数创建一个以字节为单位的给定长度的新 <code>ArrayBuffer</code> 对象。</p><ul><li><code>length</code> ：创建的数组缓冲区的大小（以字节为单位）。</li><li><code>options</code> ：可选值。一个对象，可以包含下列属性： <ul><li><code>maxByteLength</code> ：数组缓冲区可调整到的最大大小（以字节为单位）。</li></ul></li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 创建一个 16 字节的缓冲区</span>
<span class="token keyword">const</span> buffer <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayBuffer</span><span class="token punctuation">(</span><span class="token number">16</span><span class="token punctuation">)</span>

<span class="token comment">// 建立 DataView 视图</span>
<span class="token keyword">const</span> dataView <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">DataView</span><span class="token punctuation">(</span>buffer<span class="token punctuation">)</span>
<span class="token comment">// 使用 getUint8 从 0 个字节处开始，获取一个无符号的 8-bit 整数 (一个字节)</span>
<span class="token comment">// 获取结果为 0 。因为原始内存的 ArrayBuffer 对象，默认所有位都是 0</span>
dataView<span class="token punctuation">.</span><span class="token function">getUint8</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span> <span class="token comment">// 0</span>

<span class="token comment">// 建立 32 位带符号整数视图</span>
<span class="token keyword">const</span> int32TypedView <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int32Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 创建一个 8 字节的缓冲区，可调整最大长度到 16 字节</span>
<span class="token keyword">const</span> resizableBuffer <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayBuffer</span><span class="token punctuation">(</span><span class="token number">8</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token literal-property property">maxByteLength</span><span class="token operator">:</span> <span class="token number">16</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token comment">// 使用 resize 方法将 ArrayBuffer 调整到 12 字节</span>
resizableBuffer<span class="token punctuation">.</span><span class="token function">resize</span><span class="token punctuation">(</span><span class="token number">12</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="arraybuffer-对象属性" tabindex="-1"><a class="header-anchor" href="#arraybuffer-对象属性" aria-hidden="true">#</a> ArrayBuffer 对象属性</h3><ul><li><p><code>ArrayBuffer.prototype.byteLength</code> ：表示一个 <code>ArrayBuffer</code> 对象的字节长度。</p></li><li><p><code>ArrayBuffer.prototype.maxByteLength</code> ：返回 <code>ArrayBuffer</code> 对象可调整大小的最大长度（以字节为单位）。</p></li><li><p><code>ArrayBuffer.prototype.resizable</code> ：返回 <code>ArrayBuffer</code> 对象是否可以调整大小。</p></li></ul><h3 id="arraybuffer-对象方法" tabindex="-1"><a class="header-anchor" href="#arraybuffer-对象方法" aria-hidden="true">#</a> ArrayBuffer 对象方法</h3><ul><li><p><code>ArrayBuffer.isView(value)</code> ：用来判断传入的参数值 <code>value</code> 是否是一种 <code>ArrayBuffer</code> 视图（view），比如类型化数组对象（<code>TypedArray</code> ）或者数据视图（<code>DataView</code>）。</p></li><li><p><code>ArrayBuffer.prototype.resize(newLength)</code> ：将 <code>ArrayBuffer</code> 对象的大小调整为指定的大小 <code>newLength</code> （以字节为单位）。</p></li><li><p><code>ArrayBuffer.prototype.slice(start, end)</code> ：返回一个新的 <code>ArrayBuffer</code> 对象，其内容是 <code>ArrayBuffer</code> 对象从 <code>begin</code>（包含）到 <code>end</code>（不包含）字节的副本。</p><ul><li><code>start</code> ：可选值。开始提取的索引值，会转换为整数。 <ul><li>如果 <code>start &lt; 0</code> ，将从末尾开始计数（即：<code>start + buffer.length</code>）。</li><li>如果 <code>start &lt; -buffer.length</code> 或 <code>start</code> 省略，则默认为 <code>0</code> 。</li><li>如果 <code>start &gt;= buffer.length</code>，则不会提取任何内容。</li></ul></li><li><code>end</code> ：可选值。结束提取的索引值，会转换为整数，但不包含结束索引值。 <ul><li>如果 <code>end &lt; 0</code> ，将从末尾开始计数（即：<code>end + arr.length</code>）。</li><li>如果 <code>end &lt; -buffer.length</code>，则使用 <code>0</code> 。</li><li>如果 <code>end &gt;= buffer.length</code> 或 <code>end</code> 省略，则默认为 <code>buffer.length</code>，会导致直到所有元素都被提取。</li><li>如果 <code>end</code> 位于 <code>start</code> 之前，则不会提取任何内容。</li></ul></li></ul></li></ul><h2 id="endianness-字节序" tabindex="-1"><a class="header-anchor" href="#endianness-字节序" aria-hidden="true">#</a> Endianness 字节序</h2><p>字节序，或字节顺序（&quot;Endian&quot;、&quot;endianness&quot; 或 &quot;byte-order&quot;），描述了计算机如何组织字节，组成对应的数字。</p><p>每个内存存储位置都有一个索引或地址。每一字节可以存储一个 8 位数字（即介于 <code>0x00</code> 和 <code>0xff</code> 之间）。对于更大的数字需要使用多个字节进行存储，多个字节的排序方式：</p><ul><li><code>little-endian</code> （小字节序、低字节序）：使用低位储存更重要的信息（类比欧洲通用日期书格式 31 December 2050 ，年份最重要在最后面，月份其次，日期最后）。</li><li><code>big-endian</code> （大字节序、高字节序）：使用高位储存更重要的信息（类比 ISO 日期格式 2050-12-31 ，年份最重要在最前面，月份其次，日期最后）。</li></ul><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code>使用不同字节序存储数字 0x12345678（即十进制中的 305 419 896）
<span class="token list punctuation">-</span> little-endian 方式： 0x78 0x56 0x34 0x12
<span class="token list punctuation">-</span> big-endian 方法： 0x12 0x34 0x56 0x78
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>字节序的使用：</p><ul><li>处理器体系 <ul><li>x86、MOS Technology 6502、Z80、VAX、PDP-11等处理器为 <code>little-endian</code> （小字节序、低字节序）；</li><li>Motorola 6800、Motorola 68000、PowerPC 970、System/370、SPARC（除V9外）等处理器为 <code>big-endian</code> （大字节序、高字节序）；</li><li>ARM、PowerPC（除PowerPC 970外）、DEC Alpha、SPARC V9、MIPS、PA-RISC及IA64的字节序是可配置的。</li></ul></li><li>网络序：互联网标准通常要求数据使用 <code>big-endian</code> 存储，也被称之为网络字节序，或网络序。从标准 Unix 套接字（socket）层开始，一直到标准化网络的二进制数据结构。</li></ul><p>如果一段数据是 <code>big-endian</code> 字节序，<code>TypedArray</code> 数组将无法正确解析，因为它只能处理 <code>little-endian</code> 字节序，所以 JavaScript 引入 <code>DataView</code> 对象，可以设定字节序。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 假定某段 buffer 包含如下字节 [0x02, 0x01, 0x03, 0x07]</span>
<span class="token keyword">const</span> buffer <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayBuffer</span><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> uint8TypedArrayView <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint8Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">)</span>
uint8TypedArrayView<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">2</span>
uint8TypedArrayView<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">1</span>
uint8TypedArrayView<span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">3</span>
uint8TypedArrayView<span class="token punctuation">[</span><span class="token number">3</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">7</span>

<span class="token keyword">const</span> uint16TypedArrayView <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint16Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">)</span>

<span class="token comment">// 计算机采用小端字节序，所以头两个字节等于 258</span>
<span class="token keyword">if</span> <span class="token punctuation">(</span>uint16TypedArrayView<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">===</span> <span class="token number">258</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;OK&#39;</span><span class="token punctuation">)</span> <span class="token comment">// &quot;OK&quot;</span>
<span class="token punctuation">}</span>

<span class="token comment">// 赋值运算</span>
uint16TypedArrayView<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">255</span> <span class="token comment">// 字节变为 [0xFF, 0x00, 0x03, 0x07]</span>
uint16TypedArrayView<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">0xff05</span> <span class="token comment">// 字节变为 [0x05, 0xFF, 0x03, 0x07]</span>
uint16TypedArrayView<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">0x0210</span> <span class="token comment">// 字节变为 [0x05, 0xFF, 0x10, 0x02]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果不确定正在使用的计算机的字节序，可以采用下面的判断方式。</p><ul><li>如果返回 true 则为 <code>little-endian</code> （小字节序、低字节序）</li><li>如果返回 false 则为 <code>big-endian</code> （大字节序、高字节序）</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> littleEndian <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> buffer <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayBuffer</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span>
  <span class="token keyword">new</span> <span class="token class-name">DataView</span><span class="token punctuation">(</span>buffer<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">setInt16</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">256</span><span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">)</span>
  <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">Int16Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">)</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">===</span> <span class="token number">256</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="typedarray-视图" tabindex="-1"><a class="header-anchor" href="#typedarray-视图" aria-hidden="true">#</a> TypedArray 视图</h2><h3 id="typedarray-视图概述" tabindex="-1"><a class="header-anchor" href="#typedarray-视图概述" aria-hidden="true">#</a> TypedArray 视图概述</h3><p><code>TypedArray</code> 视图从 <code>ArrayBuffer</code> 对象中<strong>读写简单类型</strong>的二进制数据。包含类型的视图如下，每一种视图都是一种构造函数。</p><ul><li><code>Int8Array</code> ：8 位有符号整型（补码），长度 1 字节。</li><li><code>Uint8Array</code> ：8 位无符号整型，长度 1 字节。</li><li><code>Uint8ClampedArray</code> ：8 位无符号整型，长度 1 字节。</li><li><code>Int16Array</code> ：16 位有符号整型（补码），长度 2 字节。</li><li><code>Uint16Array</code> ：16 位无符号整型，长度 2 字节。</li><li><code>Int32Array</code> ：32 位有符号整型（补码），长度 4 字节。</li><li><code>Uint32Array</code> ：32 位无符号整型，长度 4 字节。</li><li><code>Float32Array</code> ：32 位 IEEE 浮点数（7 位有效数字），长度 4 字节。</li><li><code>Float64Array</code> ：64 位 IEEE 浮点数（16 位有效数字），长度 8 字节。</li><li><code>BigInt64Array</code> ：64 位有符号整型（补码），长度 8 字节。</li><li><code>BigUint64Array</code> ：64 位无符号整型，长度 8 字节。</li></ul><p>普通数组与 <code>TypedArray</code> 数组的差异：</p><ul><li><code>TypedArray</code> 数组的所有成员，都是同一种类型。</li><li><code>TypedArray</code> 数组的成员是连续的，不会有空位。</li><li><code>TypedArray</code> 数组成员的默认值为 0。比如，<code>new Array(10)</code> 返回一个普通数组，里面没有任何成员，只是 10 个空位；<code>new Uint8Array(10)</code> 返回一个 <code>TypedArray</code> 数组，里面 10 个成员都是 0。</li><li><code>TypedArray</code> 数组只是一层视图，本身不储存数据，它的数据都储存在底层的 <code>ArrayBuffer</code> 对象之中，要获取底层对象必须使用 <code>buffer</code> 属性。</li></ul><h3 id="typedarray-构造函数" tabindex="-1"><a class="header-anchor" href="#typedarray-构造函数" aria-hidden="true">#</a> TypedArray 构造函数</h3><ul><li><p><code>new TypedArray(buffer, byteOffset, length)</code> ：使用 <code>ArrayBuffer</code> 或 <code>SharedArrayBuffer</code> 实例，创建一个新的指定缓冲区的类型化数组视图。</p><ul><li><code>buffer</code> ： <code>ArrayBuffer</code> 或 <code>SharedArrayBuffer</code> 实例。</li><li><code>byteOffset</code> ：可选值。视图开始的字节序号，默认从 <code>0</code> 开始。</li><li><code>length</code> ：可选值。视图包含的数据个数，默认直到本段内存区域结束。</li></ul><p><code>byteOffset</code> 必须与所要建立的数据类型一致，否则会报错。如果想从任意字节开始解读 <code>ArrayBuffer</code> 对象，必须使用 <code>DataView</code> 视图，<code>TypedArray</code> 视图为固定的解读格式。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 创建一个 8 字节的 ArrayBuffer</span>
<span class="token keyword">const</span> buffer <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayBuffer</span><span class="token punctuation">(</span><span class="token number">8</span><span class="token punctuation">)</span>

<span class="token comment">// 创建一个指向 buffer 的 Int32 视图，开始于字节 0，直到缓冲区的末尾</span>
<span class="token keyword">const</span> int32TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int32Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">)</span>
<span class="token comment">// 创建一个指向 buffer 的 Uint8 视图，开始于字节 2，直到缓冲区的末尾</span>
<span class="token keyword">const</span> uint8TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint8Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>
<span class="token comment">// 创建一个指向 buffer 的 Int16 视图，开始于字节 2，长度为 2</span>
<span class="token keyword">const</span> int16TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int16Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>

<span class="token comment">// byteOffset 必须对齐</span>
<span class="token keyword">const</span> int16TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int16Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span>
<span class="token comment">// Uncaught RangeError: start offset of Int16Array should be a multiple of 2</span>
<span class="token comment">// 新生成一个 8 个字节的 ArrayBuffer 对象，然后在这个对象的第一个字节，建立带符号的 16 位整数视图，结果报错。</span>
<span class="token comment">// 当将 TypedArray 构建为 ArrayBuffer 的视图时，byteOffset 参数必须与其元素大小对齐；换句话说，偏移量必须是 BYTES_PER_ELEMENT 的倍数。</span>
<span class="token keyword">const</span> int16TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int16Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// byteLength 必须对齐</span>
<span class="token keyword">const</span> int32TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int32Array</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token class-name">ArrayBuffer</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// Uncaught RangeError: byte length of Int32Array should be a multiple of 4</span>
<span class="token comment">// ArrayBuffer 传递给 TypedArray 构造函数的 byteLength 属性必须是构造函数 BYTES_PER_ELEMENT 的倍数。</span>
<span class="token keyword">const</span> int32TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int32Array</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token class-name">ArrayBuffer</span><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><code>new TypedArray(length)</code> ：<code>TypedArray</code> 构造函数可以不通过 <code>ArrayBuffer</code> 对象，直接分配内存而生成生成 <code>TypedArray</code> 实例。</p><ul><li><code>length</code> ：指定 <code>TypedArray</code> 视图的长度。在内存中创建一个内部数组缓冲区，大小长度乘以 <code>BYTES_PER_ELEMENT</code> 字节（每个元素占用的字节数），用 <code>0</code> 填充。省略所有参数，等同于使用 <code>0</code> 作为参数。</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 创建一个 8 个成员的 Float64Array 数组（共 64 字节）</span>
<span class="token comment">// 可以不通过 ArrayBuffer 对象，直接分配内存而生成</span>
<span class="token keyword">const</span> float64TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Float64Array</span><span class="token punctuation">(</span><span class="token number">8</span><span class="token punctuation">)</span>

<span class="token comment">// 依次对每个成员赋值</span>
float64TypedArray<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">10</span>
float64TypedArray<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">20</span>
float64TypedArray<span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">]</span> <span class="token operator">=</span> float64TypedArray<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">+</span> float64TypedArray<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><code>new TypedArray(typedArray)</code> ：<code>TypedArray</code> 构造函数可以接受另一个 <code>TypedArray</code> 实例作为参数，生成 <code>TypedArray</code> 实例。</p><p>生成的新数组，只是复制了参数数组的值，对应的底层内存是不一样的。新数组会开辟一段新的内存储存数据，不会在原数组的内存之上建立视图。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// Int8Array 构造函数接受一个 Uint8Array 实例作为参数。</span>
<span class="token keyword">const</span> int8TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int8Array</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token class-name">Uint8Array</span><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">)</span><span class="token punctuation">)</span>

<span class="token keyword">const</span> int8TypedArray1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int8Array</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span>

<span class="token comment">// int8TypedArray2 以数组 int8TypedArray1 为模版生成</span>
<span class="token comment">// int8TypedArray1 改变的时候，int8TypedArray2 不会改变</span>
<span class="token keyword">const</span> int8TypedArray2 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int8Array</span><span class="token punctuation">(</span>int8TypedArray1<span class="token punctuation">)</span>
<span class="token comment">// int8TypedArray3 与 int8TypedArray1 基于同一段内存，构建不同的视图</span>
<span class="token comment">// int8TypedArray1 改变的时候，int8TypedArray3 会改变</span>
<span class="token keyword">const</span> int8TypedArray3 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int8Array</span><span class="token punctuation">(</span>int8TypedArray1<span class="token punctuation">.</span>buffer<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><code>new TypedArray(object)</code> ：<code>TypedArray</code> 构造函数可以接受一个普通对象 <code>object</code> ，生成 <code>TypedArray</code> 实例。</p><p><code>TypedArray</code> 视图会重新开辟内存，不会在原数组的内存上建立视图。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 从一个普通的数组，生成一个 8 位无符号整数的 TypedArray 实例</span>
<span class="token keyword">const</span> uint8TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint8Array</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span><span class="token punctuation">)</span>

<span class="token comment">// 可以使用以下方式，将 TypedArray 数组转换回普通数组</span>
<span class="token keyword">const</span> normalArray <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token operator">...</span>uint8TypedArray<span class="token punctuation">]</span>
<span class="token keyword">const</span> normalArray <span class="token operator">=</span> Array<span class="token punctuation">.</span><span class="token function">from</span><span class="token punctuation">(</span>uint8TypedArray<span class="token punctuation">)</span>
<span class="token keyword">const</span> normalArray <span class="token operator">=</span> <span class="token class-name">Array</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function">slice</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>uint8TypedArray<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul><h3 id="typedarray-视图属性" tabindex="-1"><a class="header-anchor" href="#typedarray-视图属性" aria-hidden="true">#</a> TypedArray 视图属性</h3><ul><li><p><code>TypedArray.prototype.buffer</code> ：返回类型化数组引用的 <code>ArrayBuffer</code>。</p></li><li><p><code>TypedArray.prototype.byteLength</code> ：返回类型化数组的长度（以字节为单位）。</p></li><li><p><code>TypedArray.prototype.byteOffset</code> ：返回从类型化数组距离 <code>ArrayBuffer</code> 起始位置的偏移量（以字节为单位）。</p></li><li><p><code>TypedArray.prototype.length</code> ：返回类型化数组中保存的元素个数。</p></li><li><p><code>TypedArray.prototype.BYTES_PER_ELEMENT</code> ：返回不同的 TypedArray 对象元素大小的数字值。</p></li></ul><h3 id="typedarray-视图方法" tabindex="-1"><a class="header-anchor" href="#typedarray-视图方法" aria-hidden="true">#</a> TypedArray 视图方法</h3><ul><li><p><code>TypedArray</code> 数组没有 <code>concat</code> 方法。如果想要合并多个 <code>TypedArray</code> 数组，可以用下面这个函数。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">concatenate</span><span class="token punctuation">(</span><span class="token parameter">resultConstructor<span class="token punctuation">,</span> <span class="token operator">...</span>arrays</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">let</span> totalLength <span class="token operator">=</span> <span class="token number">0</span>
  <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> arr <span class="token keyword">of</span> arrays<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    totalLength <span class="token operator">+=</span> arr<span class="token punctuation">.</span>length
  <span class="token punctuation">}</span>
  <span class="token keyword">let</span> result <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">resultConstructor</span><span class="token punctuation">(</span>totalLength<span class="token punctuation">)</span>
  <span class="token keyword">let</span> offset <span class="token operator">=</span> <span class="token number">0</span>
  <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> arr <span class="token keyword">of</span> arrays<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    result<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span>arr<span class="token punctuation">,</span> offset<span class="token punctuation">)</span>
    offset <span class="token operator">+=</span> arr<span class="token punctuation">.</span>length
  <span class="token punctuation">}</span>
  <span class="token keyword">return</span> result
<span class="token punctuation">}</span>

<span class="token function">concatenate</span><span class="token punctuation">(</span>Uint8Array<span class="token punctuation">,</span> Uint8Array<span class="token punctuation">.</span><span class="token function">of</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">,</span> Uint8Array<span class="token punctuation">.</span><span class="token function">of</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token comment">// Uint8Array [1, 2, 3, 4]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><code>TypedArray.of((element0, element1, /* ... ,*/ elementN)</code> ：创建一个具有可变数量参数的新的 <code>TypedArray</code> 实例。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>Float32Array<span class="token punctuation">.</span><span class="token function">of</span><span class="token punctuation">(</span><span class="token number">0.151</span><span class="token punctuation">,</span> <span class="token operator">-</span><span class="token number">8</span><span class="token punctuation">,</span> <span class="token number">3.7</span><span class="token punctuation">)</span>

<span class="token comment">// 方法一</span>
<span class="token keyword">let</span> uint8TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint8Array</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span>

<span class="token comment">// 方法二</span>
<span class="token keyword">let</span> uint8TypedArray <span class="token operator">=</span> Uint8Array<span class="token punctuation">.</span><span class="token function">of</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span>

<span class="token comment">// 方法三</span>
<span class="token keyword">let</span> uint8TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint8Array</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span>
uint8TypedArray<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">1</span>
uint8TypedArray<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">2</span>
uint8TypedArray<span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">3</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><code>TypedArray.from(source, mapFn, thisArg)</code> ：从一个类数组或者可迭代对象中创建一个新的 <code>TypedArray</code> 实例。</p><ul><li><code>source</code> ：需要转换为 <code>TypedArray</code> 的类数组或者可迭代对象。</li><li><code>mapFn</code> ：可选参数。如果指定了该参数，则最后生成的类型数组会经过该函数的加工处理后再返回。</li><li><code>thisArg</code> ：可选参数。执行 <code>mapFn</code> 函数时 <code>this</code> 的值。</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 使用 Set (可迭代对象)</span>
<span class="token keyword">var</span> set <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Set</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
Uint8Array<span class="token punctuation">.</span><span class="token function">from</span><span class="token punctuation">(</span>set<span class="token punctuation">)</span> <span class="token comment">// Uint8Array [ 1, 2, 3 ]</span>

<span class="token comment">// 使用字符串</span>
Int16Array<span class="token punctuation">.</span><span class="token function">from</span><span class="token punctuation">(</span><span class="token string">&#39;123&#39;</span><span class="token punctuation">)</span> <span class="token comment">// Int16Array [ 1, 2, 3 ]</span>

<span class="token comment">// 使用箭头函数对数组元素进行映射</span>
Float32Array<span class="token punctuation">.</span><span class="token function">from</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token parameter">x</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> x <span class="token operator">+</span> x<span class="token punctuation">)</span>
<span class="token comment">// Float32Array [ 2, 4, 6 ]</span>

<span class="token comment">// 生成一个数字序列</span>
Uint8Array<span class="token punctuation">.</span><span class="token function">from</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">length</span><span class="token operator">:</span> <span class="token number">5</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token parameter">v<span class="token punctuation">,</span> k</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> k<span class="token punctuation">)</span>
<span class="token comment">// Uint8Array [ 0, 1, 2, 3, 4 ]</span>

Int16Array<span class="token punctuation">.</span><span class="token function">from</span><span class="token punctuation">(</span>Int8Array<span class="token punctuation">.</span><span class="token function">of</span><span class="token punctuation">(</span><span class="token number">127</span><span class="token punctuation">,</span> <span class="token number">126</span><span class="token punctuation">,</span> <span class="token number">125</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token parameter">x</span> <span class="token operator">=&gt;</span> <span class="token number">2</span> <span class="token operator">*</span> x<span class="token punctuation">)</span>
<span class="token comment">// Int16Array [ 254, 252, 250 ]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><code>TypedArray.prototype.set(typedarray, targetOffset)</code> ：用于从指定数组中读取值，并将其存储在类型化数组中。</p><ul><li><code>typedarray</code> / <code>array</code><ul><li>如果源数组是数组，数组的所有值都会被复制到目标数组中。如果数组的长度加上偏移值 <code>targetOffset</code> 的结果超过目标数组的长度，则会抛出异常错误。</li><li>如果源数组是 <code>TypedArray</code> ，则源数组和目标数组可以共享同一个底层的 <code>ArrayBuffer</code> 。</li></ul></li><li><code>targetOffset</code> ：可选值。指定偏移量，从指定位置使用源数组值进行覆盖重写。如果忽略该参数，则默认为 0 。</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> buffer <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayBuffer</span><span class="token punctuation">(</span><span class="token number">8</span><span class="token punctuation">)</span>
<span class="token keyword">var</span> uint8TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint8Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">)</span>

uint8TypedArray<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>uint8TypedArray<span class="token punctuation">)</span> 
<span class="token comment">// Uint8Array [ 0, 0, 0, 1, 2, 3, 0, 0 ]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><code>TypedArray.prototype.subarray(begin, end)</code> ：返回一个新的、基于相同 <code>ArrayBuffer</code>、元素类型也相同的的 <code>TypedArray</code>。开始的索引将会被包括，而结束的索引将不会被包括。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> buffer <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayBuffer</span><span class="token punctuation">(</span><span class="token number">8</span><span class="token punctuation">)</span>
<span class="token keyword">var</span> uint8TypedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint8Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">)</span>

uint8TypedArray<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>uint8TypedArray<span class="token punctuation">)</span>
<span class="token comment">// Uint8Array [ 1, 2, 3, 0, 0, 0, 0, 0 ]</span>

<span class="token keyword">var</span> sub <span class="token operator">=</span> uint8TypedArray<span class="token punctuation">.</span><span class="token function">subarray</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">)</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>sub<span class="token punctuation">)</span>
<span class="token comment">// Uint8Array [ 1, 2, 3, 0 ]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>普通数组的操作方法和属性，对 <code>TypedArray</code> 数组完全适用。</p><ul><li><code>TypedArray.prototype.at()</code> ：返回给定索引处的数组元素。接受从最后一项往回计算的负整数。</li><li><code>TypedArray.prototype.copyWithin()</code> ：在数组内复制数组元素序列。</li><li><code>TypedArray.prototype.entries()</code> ：返回一个新的数组迭代器对象，其中包含数组中每个索引的键/值对。</li><li><code>TypedArray.prototype.every()</code> ：如果调用数组中的每个元素都满足测试函数，则返回 true。</li><li><code>TypedArray.prototype.fill()</code> ：用静态值填充数组中从开始索引到结束索引的所有元素。</li><li><code>TypedArray.prototype.filter()</code> ：返回一个新数组，其中包含调用所提供的筛选函数返回为 true 的所有数组元素。</li><li><code>TypedArray.prototype.find()</code> ：返回数组中满足提供的测试函数的第一个元素的值，如果没有找到合适的元素，则返回 undefined。</li><li><code>TypedArray.prototype.findIndex()</code> ：返回数组中满足提供的测试函数的第一个元素的索引，如果没有找到合适的元素，则返回 -1。</li><li><code>TypedArray.prototype.findLast()</code> ：回数组中满足提供的测试函数的最后一个元素的值，如果没有找到合适的元素，则返回 undefined。</li><li><code>TypedArray.prototype.findLastIndex()</code> ：返回数组中满足所提供测试函数的最后一个元素的索引，如果没有找到合适的元素，则返回 -1。</li><li><code>TypedArray.prototype.forEach()</code> ：对调用数组中的每个元素调用函数。</li><li><code>TypedArray.prototype.includes()</code> ：根据类型化数组是否包含一个确定的元素，来决定返回 true 还是 false 。</li><li><code>TypedArray.prototype.indexOf()</code> ：返回在调用数组中可以找到给定元素的第一个（最小）索引，如果没有找到，则返回 -1。</li><li><code>TypedArray.prototype.join()</code> ：将数组的所有元素连接为字符串。</li><li><code>TypedArray.prototype.keys()</code> ：返回一个新的数组迭代器对象，该对象包含数组中每个索引的键。</li><li><code>TypedArray.prototype.lastIndexOf()</code> ：返回在调用数组中可以找到给定元素的最后一个（最大）索引，如果找不到，则返回 -1。</li><li><code>TypedArray.prototype.map()</code> ：返回一个新数组，其中包含对调用数组中的每个元素调用函数的结果。</li><li><code>TypedArray.prototype.reduce()</code> ：对数组的每个元素（从左到右）执行用户提供的“reducer”回调函数，将其简化为单个值。</li><li><code>TypedArray.prototype.reduceRight()</code> ：对数组的每个元素（从右到左）执行用户提供的“reducer”回调函数，将其简化为单个值。</li><li><code>TypedArray.prototype.reverse()</code> ：反转数组元素的顺序——第一个成为最后一个，最后一个成为第一个。</li><li><code>TypedArray.prototype.set()</code> ：在类型化数组中存储多个值，从指定数组读取输入值。</li><li><code>TypedArray.prototype.slice()</code> ：提取调用数组的一部分并返回一个新数组。</li><li><code>TypedArray.prototype.some()</code> ：如果调用数组中至少有一个元素满足提供的测试函数，则返回 true。</li><li><code>TypedArray.prototype.values()</code> ：返回一个新的数组迭代器对象，该对象包含数组中每个索引的值。</li><li><code>TypedArray.prototype.toLocaleString()</code> ：返回一个表示调用数组及其元素的本地化字符串。</li><li><code>TypedArray.prototype.toString()</code> ：返回一个表示调用数组及其元素的字符串。</li></ul></li></ul><h3 id="arraybuffer-与字符串的互相转换" tabindex="-1"><a class="header-anchor" href="#arraybuffer-与字符串的互相转换" aria-hidden="true">#</a> ArrayBuffer 与字符串的互相转换</h3><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token doc-comment comment">/**
 * Convert ArrayBuffer/TypedArray to String via TextDecoder
 *
 * <span class="token keyword">@see</span> https://developer.mozilla.org/en-US/docs/Web/API/TextDecoder
 */</span>
<span class="token keyword">function</span> <span class="token function">ab2str</span><span class="token punctuation">(</span>
  <span class="token literal-property property">input</span><span class="token operator">:</span>
    <span class="token operator">|</span> ArrayBuffer
    <span class="token operator">|</span> Uint8Array
    <span class="token operator">|</span> Int8Array
    <span class="token operator">|</span> Uint16Array
    <span class="token operator">|</span> Int16Array
    <span class="token operator">|</span> Uint32Array
    <span class="token operator">|</span> Int32Array<span class="token punctuation">,</span>
  <span class="token literal-property property">outputEncoding</span><span class="token operator">:</span> string <span class="token operator">=</span> <span class="token string">&#39;utf8&#39;</span>
<span class="token punctuation">)</span><span class="token operator">:</span> string <span class="token punctuation">{</span>
  <span class="token keyword">const</span> decoder <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">TextDecoder</span><span class="token punctuation">(</span>outputEncoding<span class="token punctuation">)</span>
  <span class="token keyword">return</span> decoder<span class="token punctuation">.</span><span class="token function">decode</span><span class="token punctuation">(</span>input<span class="token punctuation">)</span>
<span class="token punctuation">}</span>

<span class="token doc-comment comment">/**
 * Convert String to ArrayBuffer via TextEncoder
 *
 * <span class="token keyword">@see</span> https://developer.mozilla.org/zh-CN/docs/Web/API/TextEncoder
 */</span>
<span class="token keyword">function</span> <span class="token function">str2ab</span><span class="token punctuation">(</span><span class="token parameter"><span class="token literal-property property">input</span><span class="token operator">:</span> string</span><span class="token punctuation">)</span><span class="token operator">:</span> ArrayBuffer <span class="token punctuation">{</span>
  <span class="token keyword">const</span> view <span class="token operator">=</span> <span class="token function">str2Uint8Array</span><span class="token punctuation">(</span>input<span class="token punctuation">)</span>
  <span class="token keyword">return</span> view<span class="token punctuation">.</span>buffer
<span class="token punctuation">}</span>

<span class="token doc-comment comment">/** Convert String to Uint8Array */</span>
<span class="token keyword">function</span> <span class="token function">str2Uint8Array</span><span class="token punctuation">(</span><span class="token parameter"><span class="token literal-property property">input</span><span class="token operator">:</span> string</span><span class="token punctuation">)</span><span class="token operator">:</span> Uint8Array <span class="token punctuation">{</span>
  <span class="token keyword">const</span> encoder <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">TextEncoder</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
  <span class="token keyword">const</span> view <span class="token operator">=</span> encoder<span class="token punctuation">.</span><span class="token function">encode</span><span class="token punctuation">(</span>input<span class="token punctuation">)</span>
  <span class="token keyword">return</span> view
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="溢出" tabindex="-1"><a class="header-anchor" href="#溢出" aria-hidden="true">#</a> 溢出</h3><p>不同的视图类型，所能容纳的数值范围是确定的。超出这个范围，就会出现溢出。比如，8 位视图只能容纳一个 8 位的二进制值，如果放入一个 9 位的值，就会溢出。</p><ul><li>正向溢出（overflow）：当输入值大于当前数据类型的最大值，结果等于当前数据类型的最小值加上余值（模运算的结果），再减去 1。</li><li>负向溢出（underflow）：当输入值小于当前数据类型的最小值，结果等于当前数据类型的最大值减去余值（模运算的结果）的绝对值，再加上 1。</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 创建一个带符号的 8 位整数视图</span>
<span class="token comment">// 最大值是 127，最小值是 -128</span>
<span class="token keyword">const</span> int8 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int8Array</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span>

int8<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">128</span>
<span class="token comment">// 输入值为 128 时，相当于正向溢出 1</span>
<span class="token comment">// 根据 “最小值加上余值（128 除以 127 的余值是 1），再减去 1” 的规则，则返回 -128</span>
int8<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token comment">// -128</span>

int8<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token operator">-</span><span class="token number">129</span>
<span class="token comment">// 输入值为 -129 时，相当于负向溢出 1</span>
<span class="token comment">// 根据 “最大值减去余值的绝对值（-129 除以-128 的余值的绝对值是 1），再加上 1”的规则，则返回 127</span>
int8<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token comment">// 127</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>Uint8ClampedArray</code> 视图的溢出规则：</p><ul><li>如果发生正向溢出，该值一律等于当前数据类型的最大值，即 255 ；</li><li>如果发生负向溢出，该值一律等于当前数据类型的最小值，即 0 。</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> uint8c <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint8ClampedArray</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span>

uint8c<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">256</span>
uint8c<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token comment">// 255 ，正向溢出</span>

uint8c<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token operator">-</span><span class="token number">1</span>
uint8c<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token comment">// 0 ，负向溢出</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="dataview-视图" tabindex="-1"><a class="header-anchor" href="#dataview-视图" aria-hidden="true">#</a> DataView 视图</h2><h3 id="dataview-视图概述" tabindex="-1"><a class="header-anchor" href="#dataview-视图概述" aria-hidden="true">#</a> DataView 视图概述</h3><p>在同一段内存中，依次存放不同类型的数据。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> buffer <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayBuffer</span><span class="token punctuation">(</span><span class="token number">24</span><span class="token punctuation">)</span>

<span class="token keyword">const</span> idView <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint32Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> usernameView <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint8Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">16</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> amountDueView <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Float32Array</span><span class="token punctuation">(</span>buffer<span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span>

<span class="token comment">// 将一个 24 字节长度的 ArrayBuffer 对象，分成三个部分：</span>
<span class="token comment">// &gt; 字节 0 到字节 3 ：1 个 32 位无符号整数</span>
<span class="token comment">// &gt; 字节 4 到字节 19 ：16 个 8 位整数</span>
<span class="token comment">// &gt; 字节 20 到字节 23 ：1 个 32 位浮点数</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>DataView</code> 视图可以从 <code>ArrayBuffer</code> 对象中<strong>读写复杂类型</strong>的二进制数据。</p><p><code>new DataView(buffer, byteOffset, byteLength)</code> ： <code>DataView</code> 构造函数可以接受另一个 <code>ArrayBuffer</code> 对象作为参数，生成 <code>DataView</code> 视图。</p><ul><li><code>buffer</code> ： <code>ArrayBuffer</code> 或 <code>SharedArrayBuffer</code> 实例。</li><li><code>byteOffset</code> ：可选值。视图开始的字节序号，默认从 <code>0</code> 开始。</li><li><code>byteLength</code> ：可选值。视图包含的数据个数，默认直到本段内存区域结束。</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> buffer <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayBuffer</span><span class="token punctuation">(</span><span class="token number">16</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> view <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">DataView</span><span class="token punctuation">(</span>buffer<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span>

view<span class="token punctuation">.</span><span class="token function">setInt16</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">42</span><span class="token punctuation">)</span>
view<span class="token punctuation">.</span><span class="token function">getInt16</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">// 42</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="dataview-视图属性" tabindex="-1"><a class="header-anchor" href="#dataview-视图属性" aria-hidden="true">#</a> DataView 视图属性</h3><ul><li><p><code>DataView.prototype.buffer</code> ：返回类型化数组引用的 <code>ArrayBuffer</code>。</p></li><li><p><code>DataView.prototype.byteLength</code> ：返回类型化数组的长度（以字节为单位）。</p></li><li><p><code>DataView.prototype.byteOffset</code> ：返回从类型化数组距离 <code>ArrayBuffer</code> 起始位置的偏移量（以字节为单位）。</p></li></ul><h3 id="dataview-视图方法" tabindex="-1"><a class="header-anchor" href="#dataview-视图方法" aria-hidden="true">#</a> DataView 视图方法</h3><ul><li><code>DataView.prototype.getInt8()</code> ：获取一个有符号的 8-bit 整数（1 个字节）。</li><li><code>DataView.prototype.getUint8()</code> ：获取一个无符号的 8-bit 整数（1 个字节）。</li><li><code>DataView.prototype.getInt16()</code> ：获取一个有符号短整型的 16-bit 整数（2 个字节）。</li><li><code>DataView.prototype.getUint16()</code> ：获取一个无符号短整型的 16-bit 整数（2 个字节）。</li><li><code>DataView.prototype.getInt32()</code> ：获取一个有符号长整型的 32-bit 整数（4 个字节）。</li><li><code>DataView.prototype.getUint32()</code> ：获取一个无符号长整型的 32-bit 整数（4 个字节）。</li><li><code>DataView.prototype.getFloat32()</code> ：获取一个单精度浮点数的 32-bit 整数（4 个字节）。</li><li><code>DataView.prototype.getFloat64()</code> ：获取一个双精度浮点型的 64-bit 整数（8 个字节）。</li><li><code>DataView.prototype.getBigInt64()</code> ：获取一个有符号的 64-bit 整数（8 个字节）。</li><li><code>DataView.prototype.getBigUint64()</code> ：获取一个无符号的 64-bit 整数（8 个字节）。</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> buffer <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayBuffer</span><span class="token punctuation">(</span><span class="token number">24</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> bufferDataView <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">DataView</span><span class="token punctuation">(</span>buffer<span class="token punctuation">)</span>

bufferDataView<span class="token punctuation">.</span><span class="token function">getUint8</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span> <span class="token comment">// 从第 1 个字节读取一个 8 位无符号整数</span>
bufferDataView<span class="token punctuation">.</span><span class="token function">getUint16</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">// 从第 2 个字节读取一个 16 位无符号整数</span>
bufferDataView<span class="token punctuation">.</span><span class="token function">getUint16</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span> <span class="token comment">// 从第 4 个字节读取一个 16 位无符号整数</span>

<span class="token comment">// 如果一次读取两个或两个以上字节，须明确数据的存储方式</span>
<span class="token comment">// 默认情况下，get 方法使用 big-endian （大字节序、高字节序） 解读数据</span>
<span class="token comment">// 如需使用 little-endian （小字节序、低字节序）解读，需设置 get 方法的第二个参数为 true</span>

bufferDataView<span class="token punctuation">.</span><span class="token function">getUint8</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">)</span> <span class="token comment">// 使用 little-endian （小字节序、低字节序）读取</span>
bufferDataView<span class="token punctuation">.</span><span class="token function">getUint16</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span> <span class="token comment">// 使用 big-endian （小字节序、低字节序）读取</span>
bufferDataView<span class="token punctuation">.</span><span class="token function">getUint16</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span> <span class="token comment">// // 使用 big-endian （小字节序、低字节序）读取</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>DataView.prototype.setInt8()</code> ：储存一个 8-bit 整数（1 个字节）。</li><li><code>DataView.prototype.setUint8()</code> ：储存一个无符号的 8-bit 整数（1 个字节）。</li><li><code>DataView.prototype.setInt16()</code> ：储存一个有符号短整型的 16-bit 整数（2 个字节）。</li><li><code>DataView.prototype.setUint16()</code> ：储存一个无符号短整型的 16-bit 整数（2 个字节）。</li><li><code>DataView.prototype.setInt32()</code> ：储存一个有符号长整型的 32-bit 整数（4 个字节）。</li><li><code>DataView.prototype.setUint32()</code> ：储存一个无符号长整型的 32-bit 整数（4 个字节）。</li><li><code>DataView.prototype.setFloat32()</code> ：储存一个单精度浮点数的 32-bit 整数（4 个字节）。</li><li><code>DataView.prototype.setFloat64()</code> ：储存一个双精度浮点型的 64-bit 整数（8 个字节）。</li><li><code>DataView.prototype.setBigInt64()</code> ：储存一个有符号的 64-bit 整数（8 个字节）。</li><li><code>DataView.prototype.setBigUint64()</code> ：储存一个无符号的 64-bit 整数（8 个字节）。</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> buffer <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayBuffer</span><span class="token punctuation">(</span><span class="token number">24</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> bufferDataView <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">DataView</span><span class="token punctuation">(</span>buffer<span class="token punctuation">)</span>

<span class="token comment">// 在第 1 个字节，以 big-endian （小字节序、低字节序）写入值为 25 的 32 位整数</span>
bufferDataView<span class="token punctuation">.</span><span class="token function">setInt32</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">25</span><span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span>

<span class="token comment">// 在第 5 个字节，以 big-endian （小字节序、低字节序）写入值为 25 的 32 位整数</span>
bufferDataView<span class="token punctuation">.</span><span class="token function">setInt32</span><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">25</span><span class="token punctuation">)</span>

<span class="token comment">// 在第 9 个字节，以 little-endian （小字节序、低字节序）写入值为 2.5 的 32 位浮点数</span>
bufferDataView<span class="token punctuation">.</span><span class="token function">setFloat32</span><span class="token punctuation">(</span><span class="token number">8</span><span class="token punctuation">,</span> <span class="token number">2.5</span><span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="arraybuffer-的应用" tabindex="-1"><a class="header-anchor" href="#arraybuffer-的应用" aria-hidden="true">#</a> ArrayBuffer 的应用</h2><h3 id="ajax" tabindex="-1"><a class="header-anchor" href="#ajax" aria-hidden="true">#</a> AJAX</h3><p>服务器通过 AJAX 操作只能返回文本数据，即 <code>responseType</code> 属性默认为 <code>text</code> 。如果明确知道返回的二进制数据类型，则可设置返回 <code>responseType</code> 属性设为 <code>arraybuffer</code>，如果不知道，可设为 <code>blob</code>。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> xhr <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">XMLHttpRequest</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
xhr<span class="token punctuation">.</span><span class="token function">open</span><span class="token punctuation">(</span><span class="token string">&#39;GET&#39;</span><span class="token punctuation">,</span> someUrl<span class="token punctuation">)</span>
xhr<span class="token punctuation">.</span>responseType <span class="token operator">=</span> <span class="token string">&#39;arraybuffer&#39;</span>

xhr<span class="token punctuation">.</span><span class="token function-variable function">onload</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">let</span> arrayBuffer <span class="token operator">=</span> xhr<span class="token punctuation">.</span>response
  <span class="token comment">// ···</span>
<span class="token punctuation">}</span>

xhr<span class="token punctuation">.</span><span class="token function-variable function">onreadystatechange</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>req<span class="token punctuation">.</span>readyState <span class="token operator">===</span> <span class="token number">4</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> arrayResponse <span class="token operator">=</span> xhr<span class="token punctuation">.</span>response
    <span class="token keyword">const</span> dataView <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">DataView</span><span class="token punctuation">(</span>arrayResponse<span class="token punctuation">)</span>
    <span class="token keyword">const</span> ints <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint32Array</span><span class="token punctuation">(</span>dataView<span class="token punctuation">.</span>byteLength <span class="token operator">/</span> <span class="token number">4</span><span class="token punctuation">)</span>

    xhrDiv<span class="token punctuation">.</span>style<span class="token punctuation">.</span>backgroundColor <span class="token operator">=</span> <span class="token string">&#39;#00FF00&#39;</span>
    xhrDiv<span class="token punctuation">.</span>innerText <span class="token operator">=</span> <span class="token string">&#39;Array is &#39;</span> <span class="token operator">+</span> ints<span class="token punctuation">.</span>length <span class="token operator">+</span> <span class="token string">&#39;uints long&#39;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

xhr<span class="token punctuation">.</span><span class="token function">send</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="canvas" tabindex="-1"><a class="header-anchor" href="#canvas" aria-hidden="true">#</a> Canvas</h3><p>Canvas 元素输出的二进制像素数据其实是 <code>TypedArray</code> 数组。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> canvas <span class="token operator">=</span> document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;myCanvas&#39;</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> ctx <span class="token operator">=</span> canvas<span class="token punctuation">.</span><span class="token function">getContext</span><span class="token punctuation">(</span><span class="token string">&#39;2d&#39;</span><span class="token punctuation">)</span>

<span class="token keyword">const</span> imageData <span class="token operator">=</span> ctx<span class="token punctuation">.</span><span class="token function">getImageData</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> canvas<span class="token punctuation">.</span>width<span class="token punctuation">,</span> canvas<span class="token punctuation">.</span>height<span class="token punctuation">)</span>
<span class="token keyword">const</span> uint8ClampedArray <span class="token operator">=</span> imageData<span class="token punctuation">.</span>data
<span class="token comment">// uint8ClampedArray 是一个 TypedArray 数组</span>
<span class="token comment">// 其的视图类型是一种针对 Canvas 元素的专有类型 Uint8ClampedArray</span>
<span class="token comment">// 该视图专门针对颜色，把每个字节解读为无符号的 8 位整数，即只能取值 0 - 255，而且发生运算的时候自动过滤高位溢出。</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="websocket" tabindex="-1"><a class="header-anchor" href="#websocket" aria-hidden="true">#</a> WebSocket</h3><p>WebSocket 可以通过 <code>ArrayBuffer</code>，发送或接收二进制数据。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> socket <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">WebSocket</span><span class="token punctuation">(</span><span class="token string">&#39;ws://127.0.0.1:8081&#39;</span><span class="token punctuation">)</span>
socket<span class="token punctuation">.</span>binaryType <span class="token operator">=</span> <span class="token string">&#39;arraybuffer&#39;</span>

<span class="token comment">// Wait until socket is open</span>
socket<span class="token punctuation">.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token string">&#39;open&#39;</span><span class="token punctuation">,</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">event</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// Send binary data</span>
  <span class="token keyword">const</span> typedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint8Array</span><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">)</span>
  socket<span class="token punctuation">.</span><span class="token function">send</span><span class="token punctuation">(</span>typedArray<span class="token punctuation">.</span>buffer<span class="token punctuation">)</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token comment">// Receive binary data</span>
socket<span class="token punctuation">.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token string">&#39;message&#39;</span><span class="token punctuation">,</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">event</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> arrayBuffer <span class="token operator">=</span> event<span class="token punctuation">.</span>data
  <span class="token comment">// ···</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="fetch-api" tabindex="-1"><a class="header-anchor" href="#fetch-api" aria-hidden="true">#</a> Fetch API</h3><p>Fetch API 取回的数据，就是 <code>ArrayBuffer</code> 对象。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">fetch</span><span class="token punctuation">(</span>url<span class="token punctuation">)</span>
  <span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">response</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> response<span class="token punctuation">.</span><span class="token function">arrayBuffer</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span>
  <span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">arrayBuffer</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="file-api" tabindex="-1"><a class="header-anchor" href="#file-api" aria-hidden="true">#</a> File API</h3><p>如果知道一个文件的二进制数据类型，也可以将这个文件读取为 <code>ArrayBuffer</code> 对象。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> fileInput <span class="token operator">=</span> document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;fileInput&#39;</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> file <span class="token operator">=</span> fileInput<span class="token punctuation">.</span>files<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span>
<span class="token keyword">const</span> reader <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">FileReader</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
reader<span class="token punctuation">.</span><span class="token function">readAsArrayBuffer</span><span class="token punctuation">(</span>file<span class="token punctuation">)</span>
reader<span class="token punctuation">.</span><span class="token function-variable function">onload</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> arrayBuffer <span class="token operator">=</span> reader<span class="token punctuation">.</span>result
  <span class="token comment">// ···</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>以处理 <code>bmp</code> 文件为例。</p><ul><li>假定 <code>file</code> 变量是一个指向 <code>bmp</code> 文件的文件对象，首先读取文件。</li><li>然后，定义处理图像的回调函数：先在二进制数据之上建立一个 <code>DataView</code> 视图，再建立一个 <code>bitmap</code> 对象，用于存放处理后的数据。</li><li>最后，将图像展示在 Canvas 元素之中。</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> reader <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">FileReader</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
reader<span class="token punctuation">.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token string">&#39;load&#39;</span><span class="token punctuation">,</span> processimage<span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span>
reader<span class="token punctuation">.</span><span class="token function">readAsArrayBuffer</span><span class="token punctuation">(</span>file<span class="token punctuation">)</span>

<span class="token keyword">function</span> <span class="token function">processimage</span><span class="token punctuation">(</span><span class="token parameter">e</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> buffer <span class="token operator">=</span> e<span class="token punctuation">.</span>target<span class="token punctuation">.</span>result
  <span class="token keyword">const</span> datav <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">DataView</span><span class="token punctuation">(</span>buffer<span class="token punctuation">)</span>
  <span class="token keyword">const</span> bitmap <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>
  <span class="token comment">// 具体的处理步骤</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="sharedarraybuffer" tabindex="-1"><a class="header-anchor" href="#sharedarraybuffer" aria-hidden="true">#</a> SharedArrayBuffer</h2><p><code>SharedArrayBuffer</code> 对象用来表示一个通用的、固定长度的原始二进制数据缓冲区，</p><ul><li><code>SharedArrayBuffer</code> 对象可以用来在共享内存（shared memory）上创建视图。</li><li>类似于 <code>ArrayBuffer</code> 对象，<code>ArrayBuffer</code> 对象无法共享数据。</li><li>与 <code>ArrayBuffer</code> 不同的是，<code>SharedArrayBuffer</code> 不能被转移。</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 主线程</span>
<span class="token keyword">const</span> worker <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Worker</span><span class="token punctuation">(</span><span class="token string">&#39;myworker.js&#39;</span><span class="token punctuation">)</span>

<span class="token comment">// 新建 1KB 共享内存</span>
<span class="token keyword">const</span> sharedBuffer <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">SharedArrayBuffer</span><span class="token punctuation">(</span><span class="token number">1024</span><span class="token punctuation">)</span>

<span class="token comment">// 主线程将共享内存的地址发送出去</span>
worker<span class="token punctuation">.</span><span class="token function">postMessage</span><span class="token punctuation">(</span>sharedBuffer<span class="token punctuation">)</span>

<span class="token comment">// 在共享内存上建立视图，供写入数据</span>
<span class="token keyword">const</span> sharedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int32Array</span><span class="token punctuation">(</span>sharedBuffer<span class="token punctuation">)</span>

<span class="token comment">// Worker 线程从事件的 data 属性上面取到数据。</span>
<span class="token function-variable function">onmessage</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">ev</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 主线程共享的数据，就是 1KB 的共享内存</span>
  <span class="token keyword">const</span> sharedBuffer <span class="token operator">=</span> ev<span class="token punctuation">.</span>data

  <span class="token comment">// 在共享内存上建立视图，方便读写</span>
  <span class="token keyword">const</span> sharedArray <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int32Array</span><span class="token punctuation">(</span>sharedBuffer<span class="token punctuation">)</span>

  <span class="token comment">// ...</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="atomics-对象" tabindex="-1"><a class="header-anchor" href="#atomics-对象" aria-hidden="true">#</a> Atomics 对象</h2><p><code>Atomics</code> 对象提供了一组静态方法对 <code>SharedArrayBuffer</code> 和 <code>ArrayBuffer</code> 对象进行原子操作。</p><ul><li>原子操作：多个共享内存的线程能够同时读写同一位置上的数据。原子操作会确保正在读或写的数据的值是符合预期的，即下一个原子操作一定会在上一个原子操作结束后才会开始，其操作过程不会中断。</li><li>等待和通知：<code>wait()</code> 和 <code>notify()</code> 方法采用的是 Linux 上的 <code>futexes</code> 模型（“快速用户空间互斥量”），可以让进程一直等待直到某个特定的条件为真，主要用于实现阻塞。</li></ul><p><code>Atomics</code> 对象方法：</p><ul><li><p><code>Atomics.add()</code> ：将指定位置上的数组元素与给定的值相加，并返回相加前该元素的值。</p></li><li><p><code>Atomics.and()</code> ：将指定位置上的数组元素与给定的值相与，并返回与操作前该元素的值。</p></li><li><p><code>Atomics.compareExchange()</code> ：如果数组中指定的元素与给定的值相等，则将其更新为新的值，并返回该元素原先的值。</p></li><li><p><code>Atomics.exchange()</code> ：将数组中指定的元素更新为给定的值，并返回该元素更新前的值。</p></li><li><p><code>Atomics.isLockFree(size)</code> ：可以用来检测当前系统是否支持硬件级的原子操作。对于指定大小的数组，如果当前系统支持硬件级的原子操作，则返回 <code>true</code>；否则就意味着对于该数组，Atomics 对象中的各原子操作都只能用锁来实现。此函数面向的是技术专家。</p></li><li><p><code>Atomics.load()</code> ：返回数组中指定元素的值。</p></li><li><p><code>Atomics.notify()</code> ：唤醒等待队列中正在数组指定位置的元素上等待的线程。返回值为成功唤醒的线程数量。</p></li><li><p><code>Atomics.or()</code> ：元素与给定的值相或，并返回或操作前该元素的值。</p></li><li><p><code>Atomics.store()</code> ：将数组中指定的元素设置为给定的值，并返回该值。</p></li><li><p><code>Atomics.sub()</code> ：将指定位置上的数组元素与给定的值相减，并返回相减前该元素的值。</p></li><li><p><code>Atomics.wait()</code> ：检测数组中某个指定位置上的值是否仍然是给定值，是则保持挂起直到被唤醒或超时。返回值为 <code>&quot;ok&quot;</code>、<code>&quot;not-equal&quot;</code> 或 <code>&quot;time-out&quot;</code>。调用时，如果当前线程不允许阻塞，则会抛出异常（大多数浏览器都不允许在主线程中调用 <code>wait()</code>）。</p></li><li><p><code>Atomics.xor()</code> ：将指定位置上的数组元素与给定的值相异或，并返回异或操作前该元素的值。</p></li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> sab <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">SharedArrayBuffer</span><span class="token punctuation">(</span><span class="token number">1024</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> ta <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Uint8Array</span><span class="token punctuation">(</span>sab<span class="token punctuation">)</span>

ta<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token comment">// 0</span>
ta<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">5</span> <span class="token comment">// 5</span>

Atomics<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">12</span><span class="token punctuation">)</span> <span class="token comment">// 5</span>
Atomics<span class="token punctuation">.</span><span class="token function">load</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token comment">// 17</span>

Atomics<span class="token punctuation">.</span><span class="token function">and</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">// 17</span>
Atomics<span class="token punctuation">.</span><span class="token function">load</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token comment">// 1</span>

Atomics<span class="token punctuation">.</span><span class="token function">compareExchange</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">,</span> <span class="token number">12</span><span class="token punctuation">)</span> <span class="token comment">// 1</span>
Atomics<span class="token punctuation">.</span><span class="token function">load</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token comment">// 1</span>

Atomics<span class="token punctuation">.</span><span class="token function">exchange</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">12</span><span class="token punctuation">)</span> <span class="token comment">// 1</span>
Atomics<span class="token punctuation">.</span><span class="token function">load</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token comment">// 12</span>

Atomics<span class="token punctuation">.</span><span class="token function">isLockFree</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">// true</span>
Atomics<span class="token punctuation">.</span><span class="token function">isLockFree</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span> <span class="token comment">// true</span>
Atomics<span class="token punctuation">.</span><span class="token function">isLockFree</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span> <span class="token comment">// false</span>
Atomics<span class="token punctuation">.</span><span class="token function">isLockFree</span><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">)</span> <span class="token comment">// true</span>

Atomics<span class="token punctuation">.</span><span class="token function">or</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">// 12</span>
Atomics<span class="token punctuation">.</span><span class="token function">load</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token comment">// 13</span>

Atomics<span class="token punctuation">.</span><span class="token function">store</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">12</span><span class="token punctuation">)</span> <span class="token comment">// 12</span>

Atomics<span class="token punctuation">.</span><span class="token function">sub</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span> <span class="token comment">// 12</span>
Atomics<span class="token punctuation">.</span><span class="token function">load</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token comment">// 10</span>

Atomics<span class="token punctuation">.</span><span class="token function">xor</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">// 10</span>
Atomics<span class="token punctuation">.</span><span class="token function">load</span><span class="token punctuation">(</span>ta<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token comment">// 11</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 给定一个共享的 Int32Array</span>
<span class="token keyword">const</span> sab <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">SharedArrayBuffer</span><span class="token punctuation">(</span><span class="token number">1024</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> int32 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Int32Array</span><span class="token punctuation">(</span>sab<span class="token punctuation">)</span>

<span class="token comment">// 读取线程正在休眠并位置 0 上等待。只要该位置应为 0，它就不会继续</span>
<span class="token comment">// 但是，一旦写入线程存储了新值，写入线程将通知它并返回新值（123）</span>
Atomics<span class="token punctuation">.</span><span class="token function">wait</span><span class="token punctuation">(</span>int32<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>int32<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment">// 123</span>

<span class="token comment">// 写入线程存储一个新值并再写入完成时通知等待线程</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>int32<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment">// 0;</span>
Atomics<span class="token punctuation">.</span><span class="token function">store</span><span class="token punctuation">(</span>int32<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">123</span><span class="token punctuation">)</span>
Atomics<span class="token punctuation">.</span><span class="token function">notify</span><span class="token punctuation">(</span>int32<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,93),c=[o];function l(i,r){return s(),a("div",null,c)}const k=n(p,[["render",l],["__file","ArrayBuffer.html.vue"]]);export{k as default};
